/**
 * Regression tests for prompt-classification heuristics.
 *
 * Focuses on three areas that require targeted coverage:
 *   1. Explicit review detection — all EXPLICIT_REVIEW_KEYWORDS + word-boundary guards
 *   2. Tool-heavy implementation routing — toolHeavy flag + economy-tier prevention
 *   3. Orchestration escalation — all ORCHESTRATION_KEYWORDS + false-positive guards + threshold
 *
 * No external dependencies — Node built-ins only.
 * Run with: node --test eval/classification-regression.test.mjs
 */

import { strict as assert } from "node:assert";
import { describe, it } from "node:test";
import {
  isExplicitReviewRequest,
  isToolHeavy,
  isComplexOrchestration,
  classifyPrompt,
} from "../.github/extensions/model-router/policy.mjs";

// ---------------------------------------------------------------------------
// 1. Explicit review detection — full EXPLICIT_REVIEW_KEYWORDS coverage
// ---------------------------------------------------------------------------

describe("isExplicitReviewRequest — full keyword coverage", () => {
  // Every entry in EXPLICIT_REVIEW_KEYWORDS must produce true.
  const truePositives = [
    ["review keyword",             "please review this change"],
    ["code review phrase",         "can you do a code review of this pr"],
    ["review this phrase",         "could you review this before we merge"],
    ["review the code phrase",     "review the code in auth.js"],
    ["review my code phrase",      "review my code and leave inline comments"],
    ["audit keyword",              "audit the security module for vulnerabilities"],
    ["approval readiness phrase",  "run an approval readiness check on the branch"],
    ["approval readiness checks",  "do approval readiness checks before the release"],
    ["approve this phrase",        "approve this change for production deployment"],
    ["pr review phrase",           "pr review for the new feature branch"],
    ["find bugs phrase",           "find bugs in the payment processing module"],
    ["bug finding phrase",         "bug finding session scheduled for friday"],
    ["regression hunting phrase",  "regression hunting before the release freeze"],
    ["regression hunt phrase",     "regression hunt the latest batch of commits"],
    ["find regressions phrase",    "find regressions introduced in the v2 refactor"],
  ];

  for (const [label, prompt] of truePositives) {
    it(`detects ${label}`, () => {
      assert.ok(isExplicitReviewRequest(prompt), `Expected true for: "${prompt}"`);
    });
  }

  // Word-boundary guard: "reviewed" must NOT trigger the "review" keyword.
  // After "review" in "reviewed" the next char is 'e' (word char) → no \b boundary.
  it("does not fire on 'reviewed' past tense", () => {
    assert.ok(!isExplicitReviewRequest("i have already reviewed the pull request"));
  });

  it("does not fire on unrelated implementation prompt", () => {
    assert.ok(!isExplicitReviewRequest("implement the new caching layer"));
  });
});

// ---------------------------------------------------------------------------
// Review detection → classifyPrompt precedence
// ---------------------------------------------------------------------------

describe("classifyPrompt — explicit review always routes to reasoning tier", () => {
  // Each of these prompts activates a different EXPLICIT_REVIEW_KEYWORD.
  const reviewPrompts = [
    "audit the authentication module",
    "please do a code review of this pr",
    "find bugs in the payment service",
    "regression hunting before the release",
    "approval readiness checks for v3",
    "run a pr review on feature/login",
    "regression hunt the new changes",
  ];

  for (const prompt of reviewPrompts) {
    it(`"${prompt}" → kind=review, tier=reasoning`, () => {
      const result = classifyPrompt(prompt);
      assert.equal(result.kind, "review",     `Expected kind=review for: "${prompt}"`);
      assert.equal(result.tier, "reasoning",  `Expected tier=reasoning for: "${prompt}"`);
    });
  }

  it("review keyword beats implement keyword — review check fires first", () => {
    // "implement" is an IMPLEMENT_KEYWORD; "review" is an EXPLICIT_REVIEW_KEYWORD.
    // The review branch runs before the implement branch, so kind must be "review".
    const result = classifyPrompt("implement and then review the changes");
    assert.equal(result.kind, "review");
    assert.equal(result.tier, "reasoning");
  });
});

// ---------------------------------------------------------------------------
// 2. Tool-heavy implementation routing — isToolHeavy coverage
// ---------------------------------------------------------------------------

describe("isToolHeavy — full TOOL_KEYWORDS coverage", () => {
  const truePositives = [
    ["bash keyword",     "write a bash wrapper script"],
    ["curl keyword",     "use curl to hit the endpoint"],
    ["execute keyword",  "execute the migration script"],
    ["run keyword",      "run the integration test suite"],
    ["api keyword",      "connect to the external api"],
    ["function keyword", "add a function that parses the input"],
    ["call keyword",     "call the remote service with auth headers"],
    ["invoke keyword",   "invoke the lambda handler directly"],
    ["script keyword",   "create a script to automate backups"],
    ["command keyword",  "add a new command to the cli"],
    ["shell keyword",    "execute a shell command to verify output"],
    ["http keyword",     "send an http request to the health endpoint"],
    ["request keyword",  "submit a request to the api gateway"],
    ["endpoint keyword", "expose a new endpoint on the router"],
    ["agent keyword",    "configure an agent to poll the queue"],
  ];

  for (const [label, prompt] of truePositives) {
    it(`detects ${label}`, () => {
      assert.ok(isToolHeavy(prompt), `Expected true for: "${prompt}"`);
    });
  }

  // Word-boundary guard: "callback" must NOT trigger the "call" keyword.
  // In "callback", 'call' is followed by 'b' (word char) → no \b boundary after 'l'.
  it("does not fire on 'callback' (word-boundary guard for 'call')", () => {
    assert.ok(!isToolHeavy("use a callback to handle the response event"));
  });

  it("does not fire on plain prose with no tool keywords", () => {
    assert.ok(!isToolHeavy("explain the architecture of the new service"));
  });
});

// ---------------------------------------------------------------------------
// Tool-heavy implementation routing — classifyPrompt integration
// ---------------------------------------------------------------------------

describe("classifyPrompt — tool-heavy implementation", () => {
  it("sets toolHeavy=true when implementation contains tool keywords", () => {
    const result = classifyPrompt("implement a function that calls the api");
    assert.equal(result.kind, "implementation");
    assert.equal(result.toolHeavy, true);
  });

  it("sets toolHeavy=false for plain implementation with no tool keywords", () => {
    const result = classifyPrompt("implement a login form");
    assert.equal(result.kind, "implementation");
    assert.equal(result.toolHeavy, false);
  });

  it("tool keyword lifts complexity above 0, blocking the economy-tier shortcut", () => {
    // "show" is a LIGHT_KEYWORD; "write" is an IMPLEMENT_KEYWORD; "bash" + "script" are TOOL_KEYWORDS.
    // isToolHeavy → true → complexity += 1 → complexity = 1 (not 0).
    // The economy shortcut requires (light keyword AND complexity === 0); complexity=1 breaks it.
    const result = classifyPrompt("show me how to write a bash script");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "builder");
    assert.ok(result.complexity > 0, "tool keywords should push complexity above 0");
    assert.equal(result.toolHeavy, true);
  });
});

// ---------------------------------------------------------------------------
// 3. Orchestration escalation — isComplexOrchestration coverage
// ---------------------------------------------------------------------------

describe("isComplexOrchestration — full ORCHESTRATION_KEYWORDS coverage", () => {
  const truePositives = [
    ["parallel agents phrase", "coordinate parallel agents to handle tasks"],
    ["multiple agents phrase", "spawn multiple agents for the job"],
    ["multi-agent phrase",     "build a multi-agent pipeline for data processing"],
    ["parallel tools phrase",  "execute parallel tools to speed up the build"],
    ["tool chain phrase",      "set up a tool chain for the deployment pipeline"],
    ["chained tools phrase",   "run chained tools to transform and validate data"],
  ];

  for (const [label, prompt] of truePositives) {
    it(`detects ${label}`, () => {
      assert.ok(isComplexOrchestration(prompt), `Expected true for: "${prompt}"`);
    });
  }

  // Bare "orchestrate" / "orchestration" are intentionally excluded from the keyword
  // list to avoid false positives when tasks merely mention these concepts in prose.
  it("does not fire on bare 'orchestrate' verb", () => {
    assert.ok(!isComplexOrchestration("orchestrate the deployment steps carefully"));
  });

  it("does not fire on bare 'orchestration' noun", () => {
    assert.ok(!isComplexOrchestration("describe the orchestration pattern used in this service"));
  });

  it("does not fire on 'chain of thought' (not 'tool chain')", () => {
    assert.ok(!isComplexOrchestration("use a chain of thought approach to plan the solution"));
  });

  it("does not fire when only a partial phrase matches ('agent' alone, not 'multiple agents')", () => {
    assert.ok(!isComplexOrchestration("configure an agent to monitor the queue"));
  });
});

// ---------------------------------------------------------------------------
// Orchestration escalation — classifyPrompt threshold tests
// ---------------------------------------------------------------------------

describe("classifyPrompt — orchestration escalation threshold", () => {
  it("multi-agent keyword with low complexity (< 2) does NOT escalate to reasoning", () => {
    // Prompt: implement + "multi-agent" (orchestration) but only 4 words.
    // Complexity: isToolHeavy via 'agent' → +1, nothing else → complexity=1.
    // Escalation condition: isComplexOrchestration AND complexity >= 2 → fails at complexity=1.
    const result = classifyPrompt("implement a multi-agent task");
    assert.equal(result.kind, "implementation");
    assert.notEqual(result.tier, "reasoning",
      "low-complexity orchestration must not escalate to reasoning");
  });

  it("multi-agent + multiple files bumps complexity to >= 2 and escalates to reasoning", () => {
    // "multiple agents" → orchestration, "multiple files" → complexity +2, giving complexity >= 2.
    const result = classifyPrompt(
      "implement a system using multiple agents that processes multiple files"
    );
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "reasoning",
      "orchestration with complexity >= 2 must escalate to reasoning");
  });

  it("'tool chain' alone (complexity < 2) stays at builder tier", () => {
    // "implement" → implement path; "tool chain" → orchestration; "tool" → isToolHeavy → complexity=1.
    // 1 < 2 → escalation gate not reached.
    const result = classifyPrompt("implement a tool chain");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "builder",
      "tool chain alone must not escalate without sufficient complexity");
  });

  it("parallel agents in general task with complexity >= 2 escalates to reasoning", () => {
    // No implement/plan/debug keyword → general path.
    // "parallel agents" → orchestration; "carefully" → complexity +2 → complexity >= 2.
    const result = classifyPrompt(
      "coordinate parallel agents carefully to process the entire codebase"
    );
    assert.equal(result.tier, "reasoning",
      "general orchestration task with complexity >= 2 must escalate to reasoning");
  });
});

/**
 * Regression tests for prompt-classification heuristics.
 *
 * Focuses on three areas that are high-risk for silent regressions:
 *   1. Explicit review detection
 *   2. Tool-heavy implementation routing
 *   3. Orchestration escalation
 *
 * Uses only Node built-ins (node:assert, node:test). No dependencies required.
 * Run with: node --test tests/routing-policy.test.mjs
 */

import { strict as assert } from "node:assert";
import { describe, it } from "node:test";
import {
  EXPLICIT_REVIEW_KEYWORDS,
  ORCHESTRATION_KEYWORDS,
  isExplicitReviewRequest,
  isToolHeavy,
  isComplexOrchestration,
  classifyPrompt,
} from "../.github/extensions/model-router.eval-disabled/policy.mjs";

// ---------------------------------------------------------------------------
// 1. Explicit review detection
// ---------------------------------------------------------------------------

describe("isExplicitReviewRequest — positive matches", () => {
  const cases = [
    // Single-word anchor
    ["review", "please review this code"],
    // Multi-word phrases
    ["code review", "do a code review of this module"],
    ["review this", "review this before we ship"],
    ["review the code", "can you review the code in auth.js"],
    ["review my code", "review my code and tell me if it's good"],
    // Other explicit asks
    ["audit", "audit the API for security issues"],
    ["approve this", "approve this PR"],
    ["pr review", "can you do a pr review"],
    // Bug-finding / regression-hunting phrases that count as explicit review
    ["find bugs", "find bugs in this implementation"],
    ["bug finding", "focus on bug finding in the payment module"],
    ["regression hunting", "regression hunting across the test suite"],
    ["regression hunt", "do a regression hunt before the release"],
    ["find regressions", "find regressions introduced in the last sprint"],
    // approval-readiness
    ["approval readiness", "check approval readiness for this change"],
  ];

  for (const [label, prompt] of cases) {
    it(`matches "${label}" keyword`, () => {
      assert.ok(
        isExplicitReviewRequest(prompt),
        `Expected review detection for prompt: "${prompt}"`,
      );
    });
  }

  it("covers every entry in EXPLICIT_REVIEW_KEYWORDS", () => {
    for (const kw of EXPLICIT_REVIEW_KEYWORDS) {
      assert.ok(
        isExplicitReviewRequest(kw),
        `EXPLICIT_REVIEW_KEYWORDS entry not detected by isExplicitReviewRequest: "${kw}"`,
      );
    }
  });

  it("classifyPrompt sets kind=review and tier=reasoning for review prompts", () => {
    const result = classifyPrompt("please do a code review of the pull request");
    assert.equal(result.kind, "review");
    assert.equal(result.tier, "reasoning");
  });
});

describe("isExplicitReviewRequest — false positives must not trigger", () => {
  const falsePositives = [
    // Generic bug/security mentions without explicit review phrasing
    ["bare 'bug' should not trigger", "fix the bug in login flow"],
    ["bare 'security' should not trigger", "improve security of the auth module"],
    ["implement without review words", "implement a new caching layer"],
    // Word-boundary checks
    ["'preview' must not match 'review'", "preview the dashboard before launch"],
    ["'reviewed' must not match bare 'review'", "this code was reviewed last week"],
    // Low-signal phrases that coincidentally include letters from keywords
    ["bare 'find' without 'bugs'", "find the user by id"],
    ["'regression test' is not a review ask", "write a regression test for the login flow"],
  ];

  for (const [label, prompt] of falsePositives) {
    it(label, () => {
      assert.ok(
        !isExplicitReviewRequest(prompt),
        `Unexpected review detection for: "${prompt}"`,
      );
    });
  }
});

// ---------------------------------------------------------------------------
// 2. Tool-heavy implementation routing
// ---------------------------------------------------------------------------

describe("isToolHeavy — positive matches", () => {
  const toolPrompts = [
    ["bash", "write a bash script to list files"],
    ["curl", "use curl to fetch data from the API"],
    ["execute", "execute the migration script"],
    ["run", "run the test suite after each change"],
    ["tool", "call the search tool with the query"],
    ["api", "connect to the payments api"],
    ["function", "write a function to parse JSON"],
    ["call", "call the external endpoint with the payload"],
    ["invoke", "invoke the lambda handler directly"],
    ["script", "write a script that restarts the server"],
    ["command", "run this shell command as part of setup"],
    ["shell", "execute in a shell environment"],
    ["http", "make an http request to the service"],
    ["request", "send a request to the auth endpoint"],
    ["endpoint", "add a new endpoint for file uploads"],
    ["agent", "wire up the search agent to the pipeline"],
  ];

  for (const [label, prompt] of toolPrompts) {
    it(`detects "${label}" as tool-heavy`, () => {
      assert.ok(isToolHeavy(prompt), `Expected tool-heavy for: "${prompt}"`);
    });
  }
});

describe("isToolHeavy — word-boundary false positive protection", () => {
  const safePrompts = [
    ["'callback' must not match 'call'", "implement a callback handler"],
    ["'shellfish' must not match 'shell'", "list shellfish species in the ocean"],
    ["'bashful' must not match 'bash'", "the bashful developer committed the change"],
    ["'prefix' must not match 'fix'", "prefix each log line with a timestamp"],
    ["'exchange' must not match 'change'", "build a currency exchange widget"],
  ];

  for (const [label, prompt] of safePrompts) {
    it(label, () => {
      assert.ok(!isToolHeavy(prompt), `Unexpected tool-heavy for: "${prompt}"`);
    });
  }
});

describe("classifyPrompt — tool-heavy implementation routing", () => {
  it("implementation with tool keyword sets toolHeavy:true", () => {
    const result = classifyPrompt("implement a script that calls the payments api");
    assert.equal(result.kind, "implementation");
    assert.equal(result.toolHeavy, true);
  });

  it("implementation without tool keywords sets toolHeavy:false", () => {
    const result = classifyPrompt("implement a login page with username and password fields");
    assert.equal(result.kind, "implementation");
    assert.equal(result.toolHeavy, false);
  });

  it("tool-heavy implementation routes to builder (not economy)", () => {
    // A short tool-heavy implementation prompt has complexity 1 (one tool keyword point),
    // which means it stays in builder — economy is only for zero-complexity light tasks.
    const result = classifyPrompt("write a bash script to deploy the app");
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "builder");
    assert.equal(result.toolHeavy, true);
  });

  it("simple non-tool lightweight stays economy", () => {
    const result = classifyPrompt("what is the capital of france");
    assert.equal(result.tier, "economy");
  });

  it("non-implementation tool mention does not force builder without other signals", () => {
    // A lightweight question mentioning an API concept should not escalate to builder
    // without implementation keywords or sufficient complexity.
    const result = classifyPrompt("what is a rest api");
    // 'api' hits isToolHeavy → complexity += 1 → score=1
    // No implementation keyword → falls to general branch
    // general with toolHeavy && complexity >= 1 → builder
    assert.equal(result.tier, "builder");
  });
});

// ---------------------------------------------------------------------------
// 3. Orchestration escalation
// ---------------------------------------------------------------------------

describe("isComplexOrchestration — every phrase in ORCHESTRATION_KEYWORDS", () => {
  it("covers all entries in ORCHESTRATION_KEYWORDS", () => {
    for (const kw of ORCHESTRATION_KEYWORDS) {
      assert.ok(
        isComplexOrchestration(kw),
        `ORCHESTRATION_KEYWORDS entry not detected: "${kw}"`,
      );
    }
  });

  const orchestrationPhrases = [
    "parallel agents",
    "multiple agents",
    "multi-agent",
    "parallel tools",
    "tool chain",
    "chained tools",
  ];

  for (const phrase of orchestrationPhrases) {
    it(`detects "${phrase}"`, () => {
      assert.ok(
        isComplexOrchestration(`build a system that uses ${phrase} to complete the task`),
        `Expected orchestration detection for phrase: "${phrase}"`,
      );
    });
  }
});

describe("isComplexOrchestration — false positives must not trigger", () => {
  it("bare 'orchestrate' does not trigger (avoids documentation false positives)", () => {
    assert.ok(!isComplexOrchestration("orchestrate the deployment pipeline"));
  });

  it("bare 'orchestration' does not trigger", () => {
    assert.ok(!isComplexOrchestration("explain how orchestration works in kubernetes"));
  });

  it("single 'agent' (tool keyword) does not trigger orchestration", () => {
    assert.ok(!isComplexOrchestration("use the search agent to find the file"));
  });

  it("simple task description does not trigger", () => {
    assert.ok(!isComplexOrchestration("write a function that sorts an array"));
  });
});

describe("classifyPrompt — orchestration escalation to reasoning tier", () => {
  it("implementation with orchestration phrase and sufficient complexity → reasoning", () => {
    // complexity >= 2 required for orchestration escalation
    // 'multiple agents' + 'multiple files' → complexity 3 (multi-file +2, tool +1)
    const result = classifyPrompt(
      "implement a system with multiple agents that modifies multiple files",
    );
    assert.equal(result.kind, "implementation");
    assert.equal(result.tier, "reasoning");
  });

  it("orchestration phrase alone (low complexity) does not escalate to reasoning", () => {
    // Without additional complexity signals, complexity stays at 1 (tool keyword),
    // which is below the >= 2 threshold for orchestration escalation.
    const result = classifyPrompt("add multi-agent support");
    assert.equal(result.kind, "implementation");
    // complexity < 2 → escalation guard not met → builder tier
    assert.equal(result.tier, "builder");
  });

  it("deeply complex prompt escalates to reasoning regardless of orchestration", () => {
    // complexity >= 4 triggers reasoning on its own
    const result = classifyPrompt(
      "implement a deeply complex multi-file end-to-end solution across the entire codebase carefully and thoroughly with complete test coverage",
    );
    assert.equal(result.tier, "reasoning");
  });

  it("non-implementation orchestration routes to reasoning when complex", () => {
    // General (no implement keyword) with orchestration + complexity >= 2 → reasoning
    const result = classifyPrompt(
      "design a parallel agents system for processing multiple files",
    );
    // 'design' hits plan keywords → planning kind
    assert.equal(result.kind, "planning");
    // complexity: multi-file (+2), plan keyword (+1), tool (+1) → 4 → reasoning
    assert.equal(result.tier, "reasoning");
  });
});

