describe("dedupeCandidates", () => {
  it("removes exact id+effort duplicates", () => {
    const input = [
      { id: "m", reasoningEffort: "high" },
      { id: "m", reasoningEffort: "high" },
      { id: "n", reasoningEffort: null },
    ];
    assert.equal(dedupeCandidates(input).length, 2);
  });

  it("keeps distinct effort levels as separate entries", () => {
    const input = [
      { id: "m", reasoningEffort: "medium" },
      { id: "m", reasoningEffort: "high" },
    ];
    assert.equal(dedupeCandidates(input).length, 2);
  });
});

// ---------------------------------------------------------------------------
// orderCandidates — review diversity
// ---------------------------------------------------------------------------

describe("orderCandidates review diversity", () => {
  it("floats cross-family candidates to the front for review", () => {
    const candidates = [
      { id: "claude-sonnet-4.6", reasoningEffort: "high" },
      { id: "gpt-5.1", reasoningEffort: null },
      { id: "claude-opus-4.6", reasoningEffort: null },
    ];
    const result = orderCandidates(candidates, { kind: "review" }, "claude-sonnet-4.6");
    assert.equal(result[0].id, "gpt-5.1", "cross-family model should be first");
  });

  it("returns the list unchanged for non-review routes", () => {
    const candidates = [
      { id: "a", reasoningEffort: null },
      { id: "b", reasoningEffort: null },
    ];
    const result = orderCandidates(candidates, { kind: "implementation" }, "a");
    assert.deepEqual(result, candidates);
  });
});

// ---------------------------------------------------------------------------
// buildAdditionalContext — regression for fallback note logic
// ---------------------------------------------------------------------------

describe("buildAdditionalContext fallback note", () => {
  it("fires when review reuses the exact implementation model", () => {
    const decision = {
      kind: "review",
      complexity: 1,
      selectedModelId: "claude-sonnet-4.6",
      reasoningEffort: null,
    };
    const ctx = buildAdditionalContext(decision, "claude-sonnet-4.6", "claude-sonnet-4.6");
    assert.ok(ctx.includes("fell back"), `expected fallback note; got: ${ctx}`);
  });

  it("fires when review falls back to a same-family model", () => {
    const decision = {
      kind: "review",
      complexity: 1,
      selectedModelId: "claude-sonnet-4.5",
      reasoningEffort: null,
    };
    const ctx = buildAdditionalContext(decision, "claude-sonnet-4.5", "claude-sonnet-4.6");
    assert.ok(ctx.includes("fell back"), `expected same-family fallback note; got: ${ctx}`);
  });

  it("does NOT fire when review uses a distinct model family", () => {
    const decision = {
      kind: "review",
      complexity: 1,
      selectedModelId: "gpt-5.4",
      reasoningEffort: "high",
    };
    const ctx = buildAdditionalContext(decision, "gpt-5.4", "claude-sonnet-4.6");
    assert.ok(!ctx.includes("fell back"), `unexpected fallback note; got: ${ctx}`);
  });

  it("does not include review notes for non-review tasks", () => {
    const decision = {
      kind: "implementation",
      complexity: 1,
      selectedModelId: "gpt-5.1",
      reasoningEffort: null,
    };
    const ctx = buildAdditionalContext(decision, "gpt-5.1", "claude-sonnet-4.6");
    assert.ok(!ctx.includes("Prefer review diversity"), "no diversity note for implementation");
  });
});

// ---------------------------------------------------------------------------
// isSameModelFamily
// ---------------------------------------------------------------------------

describe("isSameModelFamily", () => {
  it("returns true for two claude-sonnet variants", () => {
    assert.ok(isSameModelFamily("claude-sonnet-4", "claude-sonnet-4.5"));
    assert.ok(isSameModelFamily("claude-sonnet-4.5", "claude-sonnet-4.6"));
  });

  it("returns false for models in different families", () => {
    assert.ok(!isSameModelFamily("claude-haiku-4.5", "gpt-5.1"));
    assert.ok(!isSameModelFamily("claude-sonnet-4.6", "gpt-5.4"));
  });

  it("returns false when either arg is null", () => {
    assert.ok(!isSameModelFamily(null, "gpt-5.1"));
    assert.ok(!isSameModelFamily("claude-opus-4.6", null));
  });
});
